Based on the reference materials and detailed specifications, here's the complete implementation for the `create_eas_database` function:

```cpp
#pragma once

#include <filesystem>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace test_create_eas_database {
  void create_eas_database() {
    // Create the data directory if it doesn't exist
    std::filesystem::create_directories("data");

    // Connect to the main database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

    // Execute the ATTACH DATABASE statement to create the EAS database
    conn | sqlgen::exec("ATTACH DATABASE 'data/eas_database.db' AS EAS_DB;");
  }
}
```

## Explanation:

