#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // Begin transaction
  auto transaction_result = sqlgen::begin_transaction(conn);
  if (!transaction_result) {
    return false;
  }

  // Read from_account balance to verify sufficient funds
  auto from_account_query = sqlgen::read<Account> | sqlgen::where("account_id"_c == from_account_id);
  auto from_account_result = from_account_query(conn);
  if (!from_account_result) {
    sqlgen::rollback(conn);
    return false;
  }
  auto from_account = from_account_result.value();

  if (from_account.balance < amount) {
    sqlgen::rollback(conn);
    return false;
  }

  // Update from_account: deduct amount with balance check
  auto update_from = sqlgen::update<Account>("balance"_c.set("balance"_c - amount)) 
                   | sqlgen::where("balance"_c >= amount && "account_id"_c == from_account_id);
  auto update_from_result = update_from(conn);
  if (!update_from_result) {
    sqlgen::rollback(conn);
    return false;
  }

  // Update to_account: add amount
  auto update_to = sqlgen::update<Account>("balance"_c.set("balance"_c + amount)) 
                   | sqlgen::where("account_id"_c == to_account_id);
  auto update_to_result = update_to(conn);
  if (!update_to_result) {
    sqlgen::rollback(conn);
    return false;
  }

  // Commit transaction
  auto commit_result = sqlgen::commit(conn);
  if (!commit_result) {
    sqlgen::rollback(conn);
    return false;
  }

  return true;
}

}  // namespace transaction_transfer_funds
