  Sale s1{.sale_id = 1, .product_id = 1, .quantity = 2, .amount = 20.0};
  Sale s2{.sale_id = 2, .product_id = 1, .quantity = 3, .amount = 30.0};
  Sale s3{.sale_id = 3, .product_id = 2, .quantity = 1, .amount = 20.0};
  insert(conn, std::vector{s1, s2, s3});

