                              TableOrQueryType, JoinsType, WhereType,
                              GroupByType, OrderByType, LimitType,
                              std::vector<std::remove_cvref_t<ToType>>>(
                 _conn, fields_, from_, joins_, where_, limit_)
          .and_then(extract_result);
    }
  }

