#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables with proper constraints
  sqlgen::create_table<User> | sqlgen::if_not_exists(conn);
  sqlgen::create_table<Friendship> | sqlgen::if_not_exists(conn);

  // Insert data
  sqlgen::write(conn, users);
  sqlgen::write(conn, friendships);

  // Query 1: Find mutual friends using SELF-JOIN
  auto mutual_friends_query = sqlgen::select_from<User, "u1">(
      "username"_t1 | sqlgen::as<"user1_name">,
      "username"_t2 | sqlgen::as<"user2_name">
    )
    | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t2)
    | sqlgen::inner_join<Friendship, "f2">("user_id2"_t2 == "user_id1"_t3)
    | sqlgen::inner_join<User, "u2">("user_id2"_t3 == "user_id"_t4)
    | sqlgen::where("user_id"_t1 < "user_id"_t4)
    | sqlgen::exists(
        sqlgen::select_from<Friendship, "f3">("user_id1"_t5 == "user_id"_t1 && "user_id2"_t5 == "user_id"_t4)
    )
    | sqlgen::group_by("user_id"_t1, "user_id"_t4)
    | sqlgen::having(sqlgen::count() > 0);

  // Query 2: Users with more than average friends
  auto avg_friends_query = sqlgen::select_from<User, "u">(
      "user_id"_t1,
      "username"_t1,
      sqlgen::count("user_id2"_t2) | sqlgen::as<"friend_count">
    )
    | sqlgen::left_join<Friendship, "f">("user_id"_t1 == "user_id1"_t2)
    | sqlgen::group_by("user_id"_t1, "username"_t1)
    | sqlgen::having(
        "friend_count"_t3 > 
        sqlgen::select_from<Friendship>(
            sqlgen::avg(sqlgen::count()) 
        ).to<std::optional<double>>
    )
    | sqlgen::order_by("friend_count"_t3.desc());

  // Query 3: Friend-of-friend relationships
  auto friend_of_friend_query = sqlgen::select_from<User, "u1">(
      "username"_t1,
      "username"_t2
    )
    | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t2)
    | sqlgen::inner_join<Friendship, "f2">("user_id2"_t2 == "user_id1"_t3)
    | sqlgen::inner_join<User, "u2">("user_id2"_t3 == "user_id"_t4)
    | sqlgen::where("user_id"_t1 != "user_id"_t4)
    | sqlgen::where(sqlgen::not_exists(
        sqlgen::select_from<Friendship, "f3">("user_id1"_t5 == "user_id"_t1 && "user_id2"_t5 == "user_id"_t4)
    ));

  // Query 4: Most connected users
  auto most_connected_query = sqlgen::select_from<User, "u">(
      "user_id"_t1,
      "username"_t1,
      sqlgen::count("user_id2"_t2) | sqlgen::as<"friend_count">
    )
    | sqlgen::left_join<Friendship, "f">("user_id"_t1 == "user_id1"_t2)
    | sqlgen::group_by("user_id"_t1, "username"_t1)
    | sqlgen::order_by("friend_count"_t3.desc());

  // Query 5: Same city recommendations
  auto recommendation_query = sqlgen::select_from<User, "u1">(
      "username"_t1,
      "username"_t2
    )
    | sqlgen::inner_join<User, "u2">("city"_t1 == "city"_t2 && "user_id"_t1 != "user_id"_t2)
    | sqlgen::where(sqlgen::not_exists(
        sqlgen::select_from<Friendship, "f">("user_id1"_t3 == "user_id"_t1 && "user_id2"_t3 == "user_id"_t2)
    ));

  // Execute all queries and collect results
  auto mutual_results = mutual_friends_query(conn);
  auto avg_results = avg_friends_query(conn);
  auto friend_of_friend_results = friend_of_friend_query(conn);
  auto most_connected_results = most_connected_query(conn);
  auto recommendation_results = recommendation_query(conn);

  // Process mutual friends results
  std::vector<FriendConnection> mutual_connections;
  for (const auto& res : mutual_results) {
    mutual_connections.push_back({
        .user1_name = res.user1_name,
        .user2_name = res.user2_name
    });
  }

  return mutual_connections;
}

}  // namespace analyze_social_network
```

