auto abs(const T& _t) {
  using Type =
      typename transpilation::ToTranspilationType<std::remove_cvref_t<T>>::Type;
  return transpilation::Operation<transpilation::Operator::abs, Type>{
      .operand1 = transpilation::to_transpilation_type(_t)};
