  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen::literals;

  // Create SQLite connection
  auto conn = sqlgen::sqlite::connect(":memory:");

  // Create table and insert data
  sqlgen::write(conn, items);

  // Build the complex arithmetic query using sqlgen operations
  auto query = sqlgen::select_from<OrderItem>(
    "item_id"_c,
    "order_id"_c, 
    "product_id"_c,
    "unit_price"_c,
    "quantity"_c,
    "discount_rate"_c,
    "tax_rate"_c,

    // Arithmetic operations
    ("unit_price"_c * "quantity"_c).as<"gross_total">(),
    (("unit_price"_c * "quantity"_c) * (1 - sqlgen::coalesce("discount_rate"_c, 0.0)/100)).as<"discounted_total">(),
    (("unit_price"_c * "quantity"_c) * (1 - sqlgen::coalesce("discount_rate"_c, 0.0)/100) * (1 + sqlgen::coalesce("tax_rate"_c, 0.0)/100)).as<"final_total">(),
    (("unit_price"_c * "quantity"_c) / "quantity"_c).as<"unit_cost">(),
    ("quantity"_c % 10).as<"quantity_group">(),
    ("unit_price"_c * 0.3).as<"estimated_profit">()
  );

  // Execute query and map results to OrderMetrics struct
  auto result = query(conn);

  // Convert to vector of OrderMetrics
  std::vector<OrderMetrics> metrics;
  for (const auto& row : result) {
    OrderMetrics metric{
      .item_id = row.item_id,
      .order_id = row.order_id,
      .product_id = row.product_id,
      .unit_price = row.unit_price,
      .quantity = row.quantity,
      .discount_rate = row.discount_rate.value_or(0.0),
      .tax_rate = row.tax_rate.value_or(0.0),
      .gross_total = row.gross_total,
      .discounted_total = row.discounted_total,
      .final_total = row.final_total,
      .unit_cost = row.unit_cost,
      .quantity_group = row.quantity_group,
      .estimated_profit = row.estimated_profit
    };
    metrics.push_back(metric);
  }

  return metrics;
}

}  // namespace calculate_order_metrics

