JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // Create tables
  sqlgen::create_table<Department>(conn).value();
  sqlgen::create_table<Employee>(conn).value();

  // Insert data
  sqlgen::insert_into<Department>(depts)(conn).value();
  sqlgen::insert_into<Employee>(emps)(conn).value();

  // INNER JOIN: Employees with assigned departments
  auto inner_query = sqlgen::select_from<Department, "d">("department_name"_t1)
      | sqlgen::inner_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
      | sqlgen::select("first_name"_t2, "last_name"_t2, "salary"_t2)
      | sqlgen::to<std::vector<JoinResult>>;

  // LEFT JOIN: All employees (including those without departments)
  auto left_query = sqlgen::select_from<Employee, "e">("first_name"_t2, "last_name"_t2, "salary"_t2)
      | sqlgen::left_join<Department, "d">("department_id"_t2 == "department_id"_t1)
      | sqlgen::select("department_name"_t1)
      | sqlgen::to<std::vector<JoinResult>>;

  // RIGHT JOIN: All departments (including those without employees)
  auto right_query = sqlgen::select_from<Department, "d">("department_name"_t1)
      | sqlgen::right_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
      | sqlgen::select("first_name"_t2, "last_name"_t2, "salary"_t2)
      | sqlgen::to<std::vector<JoinResult>>;

  // FULL JOIN: All employees and departments
  auto full_query = sqlgen::select_from<Department, "d">("department_name"_t1)
      | sqlgen::full_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
      | sqlgen::select("first_name"_t2, "last_name"_t2, "salary"_t2)
      | sqlgen::to<std::vector<JoinResult>>;

  // Execute queries and collect results
  auto inner_results = inner_query(conn).value();
  auto left_results = left_query(conn).value();
  auto right_results = right_query(conn).value();
  auto full_results = full_query(conn).value();

  return JoinAnalysis{
      .inner_join_results = inner_results,
      .left_join_results = left_results,
      .right_join_results = right_results,
      .full_join_results = full_results
  };
}

}  // namespace analyze_department_employees
```

